const payload = $input.first().json;
const teachers = Array.isArray(payload.teachers) ? payload.teachers : [];
const totals = payload.totals ?? {};
const date = payload.date ?? $now.setZone('Asia/Damascus').toFormat('yyyy-MM-dd');
const limit = 3800;

const buildDetailLines = (items, formatter, maxItems = 5) => {
  if (!Array.isArray(items) || items.length === 0) {
    return [];
  }

  const lines = items.slice(0, maxItems).map((item) => `  • ${formatter(item)}`);

  if (items.length > maxItems) {
    lines.push(`  • ... +${items.length - maxItems}`);
  }

  return lines;
};

const headerLines = [
  'تقرير المعلمين اليومي',
  `التاريخ: ${date}`,
  `الإجمالي: غياب ${totals.absences_count ?? 0} | حفظ ${totals.memorized_pages ?? 0} صفحة | جزئي راسب ${totals.failed_partial_attempts_count ?? 0} | نهائي راسب ${totals.failed_final_attempts_count ?? 0}`,
];

if (teachers.length === 0) {
  return [
    {
      json: {
        text: [...headerLines, '', 'لا توجد سجلات لهذا اليوم.'].join('\n'),
      },
    },
  ];
}

const teacherBlocks = teachers.map((summary, index) => {
  const teacherName = summary.teacher?.name ?? `معلم ${index + 1}`;
  const lines = [
    `${index + 1}. ${teacherName}`,
    `- الغياب: ${summary.absences_count ?? 0}`,
    ...buildDetailLines(summary.absences, (item) => `${item.student_name} | ${item.group_name ?? '-'}${item.status ? ` | ${item.status}` : ''}`),
    `- الحفظ: ${summary.memorization_sessions_count ?? 0} جلسة / ${summary.memorized_pages ?? 0} صفحة`,
    ...buildDetailLines(summary.memorization_entries, (item) => `${item.student_name} | ${item.pages_count} صفحة (${item.from_page}-${item.to_page})`),
    `- الجزئي الراسب: ${summary.failed_partial_attempts_count ?? 0}`,
    ...buildDetailLines(summary.failed_partial_attempts, (item) => `${item.student_name} | الجزء ${item.juz_number} | القسم ${item.part_number} | محاولة ${item.attempt_no} | أخطاء ${item.mistake_count}`),
    `- النهائي الراسب: ${summary.failed_final_attempts_count ?? 0}`,
    ...buildDetailLines(summary.failed_final_attempts, (item) => `${item.student_name} | الجزء ${item.juz_number} | محاولة ${item.attempt_no} | علامة ${item.score ?? '-'}`),
  ];

  return lines.join('\n');
});

const chunks = [];
let current = headerLines.join('\n\n');
let continuation = false;

for (const block of teacherBlocks) {
  const candidate = continuation ? `${current}\n\n${block}` : `${current}\n\n${block}`;

  if (candidate.length > limit && current !== headerLines.join('\n\n')) {
    chunks.push(current);
    current = [`تقرير المعلمين اليومي - متابعة`, `التاريخ: ${date}`, '', block].join('\n');
    continuation = true;
    continue;
  }

  current = candidate;
}

if (current.trim() !== '') {
  chunks.push(current);
}

return chunks.map((text) => ({
  json: {
    text,
  },
}));
